import com.smartquiz.config.DBConnection; import java.sql.*; public class CheckEnrollments { public static void main(String[] args) throws Exception { try (Connection conn = DBConnection.getConnection()) { System.out.println("--- Enrollments ---"); try (Statement stmt = conn.createStatement(); ResultSet rs = stmt.executeQuery("SELECT e.*, u.name as student_name, c.name as class_name FROM enrollments e JOIN users u ON e.student_id = u.id JOIN classes c ON e.class_id = c.id")) { while (rs.next()) { System.out.println(rs.getString("student_name") + " -> " + rs.getString("class_name")); } } System.out.println("--- Quizzes ---"); try (Statement stmt = conn.createStatement(); ResultSet rs = stmt.executeQuery("SELECT id, title, class_id, is_published FROM quizzes")) { while (rs.next()) { System.out.println(rs.getInt("id") + ": " + rs.getString("title") + " (Class: " + rs.getInt("class_id") + ", Published: " + rs.getBoolean("is_published") + ")"); } } } } }
